export interface ChecklistItem {
  id: string;
  title: string;
  description?: string;
  location?: string;
  tip?: string;
  isSideQuest?: boolean;
}

export interface Category {
  id: string;
  title: string;
  subtitle: string;
  iconName: string;
  color: string;
  section: string;
  requiredFor100: boolean;
  items: ChecklistItem[];
}

const mk = (
  id: string,
  title: string,
  description?: string,
  location?: string,
  tip?: string
): ChecklistItem => ({ id, title, description, location, tip });

const mkSQ = (
  id: string,
  title: string,
  description?: string,
  location?: string,
  tip?: string
): ChecklistItem => ({ id, title, description, location, tip, isSideQuest: true });

